def main():
    data = load_data()
    updated = 0
    for q in data:
        qid = q["id"]
        # Standardize true answers found in PDFs by AI review
        if qid == 163: q["answer"] = "D"
        if qid == 172: q["answer"] = "C"
        if qid == 184: q["answer"] = "A"
        if qid == 186: q["answer"] = "C" # Explanation changed slightly but answer keeps C
        if qid == 189: q["answer"] = "D"

        if qid in manual_explanations:
            q["explanation_vi"] = manual_explanations[qid]
            updated += 1
            
    save_data(data)
    print(f"Injected custom explanations for Q161 - Q190! ({updated} questions updated)")

if __name__ == "__main__":
    main()
